#include <bits/stdc++.h>
using namespace std;
const int N=5e5+5;
int n,f[N],l[N],p[N];
long long sum,ans;
vector<int> g[N];
char a[N];
void dfs(int x,int fa,int deep){
	p[deep]=x;
	if(fa && a[x]==')'){
		int left=deep-1-l[fa];
		if(a[p[left]]=='(')
			f[x]=1+f[p[left-1]],l[x]=l[p[left-1]]+deep-left+1; 
	}
	sum+=f[x];
	ans^=x*sum;
	int len=g[x].size();
	for(int i=0;i<len;i++)	
		if(g[x][i]!=fa)
			dfs(g[x][i],x,deep+1);
	sum-=f[x];
}
int main(){
	scanf("%d",&n);
	scanf("%s",a+1);
	for(int i=2,fa;i<=n;i++){
		scanf("%d",&fa);
		g[fa].push_back(i);
	}
	dfs(1,0,1);
	printf("%lld",ans);
	return 0;
}
